from typing import Any, Optional, Union, List, Dict
from dataclasses import dataclass
from collections import defaultdict

@dataclass
class ParseResult:
    """Class to store the result of a JSON parsing operation."""
    value: Any
    success: bool
    error: Optional[str] = None

class CircularReferenceError(Exception):
    """Custom exception for detecting circular references in JSON structure."""
    pass

def parse_nested_json(
    data: Any,
    path: str,
    visited: Optional[set] = None,
    max_depth: int = 100
) -> ParseResult:
    """
    Parse a deeply nested JSON structure using a dot notation path with array index support.

    Args:
        data: The JSON-like data structure to parse (dict, list, or primitive type)
        path: String path to the desired value (e.g., "user.profile.settings.theme" or "users[0].name")
        visited: Set of object IDs to track visited nodes for circular reference detection
        max_depth: Maximum recursion depth to prevent stack overflow

    Returns:
        ParseResult: Object containing the parsed value, success status, and error message if any

    Examples:
        >>> data = {
        ...     "user": {
        ...         "profile": {
        ...             "settings": {"theme": "dark"}
        ...         }
        ...     },
        ...     "users": [{"name": "John"}, {"name": "Jane"}]
        ... }
        >>> result = parse_nested_json(data, "user.profile.settings.theme")
        >>> result.value
        'dark'
        >>> result = parse_nested_json(data, "users[0].name")
        >>> result.value
        'John'
        >>> result = parse_nested_json(data, "invalid.path")
        >>> result.success
        False
    """
    if visited is None:
        visited = set()

    try:
        # Check for recursion depth
        if len(visited) > max_depth:
            return ParseResult(None, False, f"Maximum recursion depth exceeded: {max_depth}")

        # Handle empty path
        if not path:
            return ParseResult(data, True)

        # Check for circular reference
        data_id = id(data)
        if data_id in visited:
            raise CircularReferenceError("Circular reference detected in data structure")
        visited.add(data_id)

        # Split path into components
        components = path.split('.', 1)
        current_key = components[0]

        # Handle array index syntax
        array_index = None
        if '[' in current_key and ']' in current_key:
            key_parts = current_key.split('[')
            current_key = key_parts[0]
            index_str = key_parts[1].rstrip(']')
            try:
                array_index = int(index_str)
            except ValueError:
                return ParseResult(None, False, f"Invalid array index: {index_str}")

        # Handle dictionary access
        if isinstance(data, dict):
            if current_key not in data:
                return ParseResult(None, False, f"Key not found: {current_key}")
            current_data = data[current_key]

        # Handle list access if array index is specified
        elif isinstance(data, list) and array_index is not None:
            if not (0 <= array_index < len(data)):
                return ParseResult(None, False, f"Array index out of bounds: {array_index}")
            current_data = data[array_index]

        else:
            return ParseResult(None, False, f"Cannot traverse path: {current_key} on type {type(data).__name__}")

        # If there's more path to process, recurse
        if len(components) > 1:
            result = parse_nested_json(current_data, components[1], visited, max_depth)
            visited.remove(data_id)
            return result

        # If this is the last component, return the value
        visited.remove(data_id)
        return ParseResult(current_data, True)

    except Exception as e:
        if isinstance(e, CircularReferenceError):
            return ParseResult(None, False, str(e))
        return ParseResult(None, False, f"Unexpected error: {str(e)}")

